import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import scala.concurrent.ExecutionContextExecutor

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("WebhookProxyService")
    implicit val materializer: ActorMaterializer = ActorMaterializer()
    implicit val executionContext: ExecutionContextExecutor = system.dispatcher

    val allowedDestinations = Set(
      "https://api.partner1.com",
      "https://api.partner2.com"
    )

    def isAllowed(url: String): Boolean =
      allowedDestinations.exists(_.startsWith(url))

    def isInternalPrivateIP(ip: String): Boolean = {
      // Simple check for private IP ranges
      ip.startsWith("10.") ||
        ip.startsWith("172.16.") ||
        ip.startsWith("192.168.")
    }

    val route =
      pathEndOrSingleSlash {
        post {
          entity(as[String]) { url =>
            val parsedUrl = Uri(url)
            if (isAllowed(parsedUrl.scheme + "://" + parsedUrl.authority.host.value)) {
              val request = HttpRequest(uri = url)
              Http().singleRequest(request).map(_.entity.dataBytes.map(_.utf8String)).onComplete {
                case scala.util.Success(response) =>
                  complete(HttpEntity(ContentTypes.`text/plain(UTF-8)`, response))
                case scala.util.Failure(exception) =>
                  complete(StatusCodes.InternalServerError, s"Error fetching URL: ${exception.getMessage}")
              }
            } else if (isInternalPrivateIP(parsedUrl.authority.host.value)) {
              complete(StatusCodes.Forbidden, "Access to internal/private IP ranges is not allowed")
            } else {
              complete(StatusCodes.BadRequest, "Invalid destination URL")
            }
          }
        }
      }

    Http().bindAndHandle(route, "0.0.0.0", 8080)
    println("Server online at http://0.0.0.0:8080/")
  }
}